  1→"use client";
  2→
  3→import { useState } from "react";
  4→import { Button } from "@/components/ui/button";
  5→import { formatMs, formatRelativeTimestamp } from "@/lib/format-time";
  6→import {
  7→  useCronJobs,
  8→  useCronMutations,
  9→  useCronRuns,
 10→  useCronStatus,
 11→} from "../_hooks/use-cron";
 12→import { formatCronSchedule } from "../_utils/cron.util";
 13→import { CronForm } from "./cron-form";
 14→import {
 15→  type CronFormState,
 16→  type CronJob,
 17→  type CronRunLogEntry,
 18→  DEFAULT_FORM,
 19→  jobToForm,
 20→} from "./types";
 21→
 22→// ── Job item ──────────────────────────────────────────────────────────────────
 23→
 24→function JobItem({
 25→  job,
 26→  isSelected,
 27→  isBusy,
 28→  onSelect,
 29→  onEdit,
 30→  onToggle,
 31→  onRun,
 32→  onDelete,
 33→}: {
 34→  job: CronJob;
 35→  isSelected: boolean;
 36→  isBusy: boolean;
 37→  onSelect: () => void;
 38→  onEdit: () => void;
 39→  onToggle: () => void;
 40→  onRun: () => void;
 41→  onDelete: () => void;
 42→}) {
 43→  return (
 44→    <div
 45→      className={`rounded-lg border p-3 cursor-pointer transition-colors ${
 46→        isSelected ? "border-primary bg-primary/5" : "hover:bg-accent/50"
 47→      }`}
 48→      onClick={onSelect}
 49→    >
 50→      <div className="flex items-start justify-between gap-2">
 51→        <div className="min-w-0 flex-1">
 52→          <div className="font-medium text-sm truncate">{job.name}</div>
 53→          <div className="text-xs text-muted-foreground mt-0.5">
 54→            {formatCronSchedule(job)}
 55→          </div>
 56→          {job.agentId && (
 57→            <div className="text-xs text-muted-foreground mt-0.5">
 58→              Agent: {job.agentId}
 59→            </div>
 60→          )}
 61→          {job.nextRunAtMs && (
 62→            <div className="text-xs text-muted-foreground mt-0.5">
 63→              Next: {formatMs(job.nextRunAtMs)}
 64→            </div>
 65→          )}
 66→        </div>
 67→        <div className="flex flex-col items-end gap-1 shrink-0">
 68→          <span
 69→            className={`text-[10px] px-1.5 py-0.5 rounded-full font-medium ${
 70→              job.enabled
 71→                ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400"
 72→                : "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400"
 73→            }`}
 74→          >
 75→            {job.enabled ? "enabled" : "disabled"}
 76→          </span>
 77→          <span className="text-[10px] px-1.5 py-0.5 rounded-full bg-muted text-muted-foreground">
 78→            {job.sessionTarget}
 79→          </span>
 80→        </div>
 81→      </div>
 82→      <div
 83→        className="flex gap-1.5 mt-2 flex-wrap"
 84→        onClick={(e) => e.stopPropagation()}
 85→      >
 86→        <Button size="sm" variant="outline" disabled={isBusy} onClick={onEdit}>
 87→          Edit
 88→        </Button>
 89→        {/* Clone removed: creation is disabled */}
 90→        <Button
 91→          size="sm"
 92→          variant="outline"
 93→          disabled={isBusy}
 94→          onClick={onToggle}
 95→        >
 96→          {job.enabled ? "Disable" : "Enable"}
 97→        </Button>
 98→        <Button size="sm" variant="outline" disabled={isBusy} onClick={onRun}>
 99→          Run
100→        </Button>
101→        <Button
102→          size="sm"
103→          variant="outline"
104→          disabled={isBusy}
105→          onClick={onDelete}
106→        >
107→          Delete
108→        </Button>
109→      </div>
110→    </div>
111→  );
112→}
