114→// ── Run item ──────────────────────────────────────────────────────────────────
115→
116→function RunItem({ run }: { run: CronRunLogEntry }) {
117→  const statusColor =
118→    run.status === "ok"
119→      ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400"
120→      : run.status === "error"
121→        ? "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400"
122→        : "bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400";
123→
124→  return (
125→    <div className="rounded-lg border p-3">
126→      <div className="flex items-start justify-between gap-2">
127→        <div className="min-w-0 flex-1">
128→          {run.jobName && (
129→            <div className="text-xs font-medium text-muted-foreground mb-0.5">
130→              {run.jobName}
131→            </div>
132→          )}
133→          {run.summary && <div className="text-sm">{run.summary}</div>}
134→          {run.error && (
135→            <div className="text-sm text-destructive mt-1 line-clamp-2">
136→              {run.error}
137→            </div>
138→          )}
139→          <div className="flex gap-3 mt-1.5 text-xs text-muted-foreground">
140→            <span>{formatRelativeTimestamp(run.startedAtMs)}</span>
141→            {run.durationMs != null && <span>{formatMs(run.durationMs)}</span>}
142→            {run.deliveryStatus && run.deliveryStatus !== "not-requested" && (
143→              <span className="capitalize">{run.deliveryStatus}</span>
144→            )}
145→          </div>
146→        </div>
147→        <span
148→          className={`text-[10px] px-1.5 py-0.5 rounded-full font-medium shrink-0 ${statusColor}`}
149→        >
150→          {run.status}
151→        </span>
152→      </div>
153→    </div>
154→  );
155→}
