158→
159→export function CronView({ sandboxId }: { sandboxId: string }) {
160→  // Form state
161→  const [form, setForm] = useState<CronFormState>(DEFAULT_FORM);
162→  const [editingJobId, setEditingJobId] = useState<string | null>(null);
163→
164→  // Jobs filter state
165→  const [includeDisabledJobs, setIncludeDisabledJobs] = useState(false);
166→
167→  // Runs filter state
168→  const [selectedJobId, setSelectedJobId] = useState<string | null>(null);
169→  const [runsLimit, setRunsLimit] = useState(50);
170→
171→  // Queries
172→  const {
173→    data: status,
174→    isLoading: statusLoading,
175→    refetch: refetchStatus,
176→  } = useCronStatus(sandboxId);
177→
178→  const {
179→    data: jobsData,
180→    isLoading: jobsLoading,
181→    refetch: refetchJobs,
182→  } = useCronJobs(sandboxId, {
183→    includeDisabled: includeDisabledJobs,
184→  });
185→
186→  const {
187→    data: runsData,
188→    isLoading: runsLoading,
189→    refetch: refetchRuns,
190→  } = useCronRuns(sandboxId, {
191→    jobId: selectedJobId,
192→    limit: runsLimit,
193→  });
194→
195→  const { edit, remove, toggle, run, busy } = useCronMutations(sandboxId);
196→
197→  const jobs = jobsData?.jobs ?? [];
198→  const jobsTotal = jobsData?.total ?? 0;
199→
200→  const runs = runsData?.runs ?? [];
201→  const runsTotal = runsData?.total ?? 0;
202→  const runsHasMore = runs.length < runsTotal;
203→
204→  // Handlers
205→  function handleRefresh() {
206→    void refetchStatus();
207→    void refetchJobs();
208→    void refetchRuns();
209→  }
210→
211→  function handleSelectJob(job: CronJob) {
212→    setSelectedJobId(job.id);
213→  }
214→
215→  function handleEdit(job: CronJob) {
216→    setEditingJobId(job.id);
217→    setForm(jobToForm(job));
218→  }
219→
220→  // Clone/creation disabled; no handler.
221→
222→  function handleCancelEdit() {
223→    setEditingJobId(null);
224→    setForm(DEFAULT_FORM);
225→  }
226→
227→  function handleSubmit() {
228→    const payload = {
229→      sandboxId,
230→      name: form.name,
231→      description: form.description || undefined,
232→      agentId: form.clearAgent ? undefined : form.agentId || undefined,
233→      clearAgent: form.clearAgent,
234→      enabled: form.enabled,
235→      scheduleKind: form.scheduleKind,
236→      scheduleAt: form.scheduleAt || undefined,
237→      everyAmount: form.everyAmount || undefined,
238→      everyUnit: form.everyUnit,
239→      cronExpr: form.cronExpr || undefined,
240→      cronTz: form.cronTz || undefined,
241→      scheduleExact: form.scheduleExact,
242→      stagger: form.stagger || undefined,
243→      sessionTarget: form.sessionTarget,
244→      payloadKind: form.payloadKind,
245→      payloadText: form.payloadText,
246→      payloadModel: form.payloadModel || undefined,
247→      payloadThinking: form.payloadThinking || undefined,
248→      timeoutSeconds: form.timeoutSeconds || undefined,
249→      expectFinal: form.expectFinal,
250→      deliveryMode: form.deliveryMode,
251→      deliveryChannel: form.deliveryChannel || undefined,
252→      deliveryTo: form.deliveryTo || undefined,
253→      deliveryBestEffort: form.deliveryBestEffort,
254→      deleteAfterRun: form.deleteAfterRun,
255→      keepAfterRun: form.keepAfterRun,
256→    };
257→
258→    if (!editingJobId) return; // Creation disabled
259→    edit.mutate({ ...payload, jobId: editingJobId });
260→    handleCancelEdit();
261→  }
262→
263→  return (
264→    <section className="flex flex-col gap-6 p-6 md:p-8">
265→      <div className="flex justify-between items-center">
266→        <div>
267→          <h1 className="text-xl font-semibold tracking-tight">Cron</h1>
268→          <p className="mt-0.5 text-sm text-muted-foreground">
269→            Schedule jobs to run at specific times or intervals.
270→          </p>
271→        </div>
272→
273→        <Button type="button" disabled={statusLoading} onClick={handleRefresh}>
274→          {statusLoading ? "Refreshing..." : "Refresh"}
275→        </Button>
276→      </div>
277→      <div className=" space-y-4">
278→        {/* Summary strip */}
279→        <div className="rounded-lg border p-4 bg-card flex items-center justify-between gap-4 flex-wrap">
280→          <div className="flex gap-6">
281→            <div>
282→              <div className="text-xs text-muted-foreground">Enabled</div>
283→              {status ? (
284→                <span
285→                  className={`text-sm font-medium ${
286→                    status.enabled
287→                      ? "text-green-600 dark:text-green-400"
288→                      : "text-red-500 dark:text-red-400"
289→                  }`}
290→                >
291→                  {status.enabled ? "Yes" : "No"}
292→                </span>
293→              ) : (
294→                <span className="block h-4 w-8 mt-0.5 rounded bg-muted animate-pulse" />
295→              )}
296→            </div>
297→            <div>
298→              <div className="text-xs text-muted-foreground">Jobs</div>
299→              {status ? (
300→                <span className="text-sm font-medium">{status.jobs}</span>
301→              ) : (
302→                <span className="block h-4 w-6 mt-0.5 rounded bg-muted animate-pulse" />
303→              )}
304→            </div>
305→            <div>
306→              <div className="text-xs text-muted-foreground">Next wake</div>
307→              {status ? (
308→                <span className="text-sm font-medium">
309→                  {formatRelativeTimestamp(status.nextWakeAtMs)}
310→                </span>
311→              ) : (
312→                <span className="block h-4 w-24 mt-0.5 rounded bg-muted animate-pulse" />
313→              )}
314→            </div>
315→          </div>
316→        </div>
317→
318→        {/* Workspace */}
319→        <div className="grid grid-cols-1 lg:grid-cols-5 gap-4 items-start">
320→          {/* Left: Jobs + Runs */}
321→          <div className="lg:col-span-3 space-y-4">
322→            {/* Jobs card */}
323→            <div className="rounded-lg border p-4 bg-card">
324→              <div className="flex items-start justify-between gap-4 mb-3">
325→                <div>
326→                  <h3 className="font-semibold">Jobs</h3>
327→                  <p className="text-sm text-muted-foreground">
328→                    All scheduled jobs in the gateway.
329→                  </p>
330→                </div>
331→                <span className="text-sm text-muted-foreground shrink-0">
332→                  {jobsTotal} job{jobsTotal !== 1 ? "s" : ""}
333→                </span>
334→              </div>
335→
336→              {/* Jobs filters */}
337→              <div className="flex flex-wrap gap-2 mb-3">
338→                <label className="flex items-center gap-2 text-sm cursor-pointer">
339→                  <input
340→                    type="checkbox"
341→                    checked={includeDisabledJobs}
342→                    onChange={(e) => {
343→                      setIncludeDisabledJobs(e.target.checked);
344→                      handleCancelEdit();
345→                    }}
346→                  />
347→                  Include disabled
348→                </label>
349→              </div>
350→
351→              {jobsLoading ? (
352→                <p className="text-sm text-muted-foreground">Loading jobs...</p>
353→              ) : jobs.length === 0 ? (
354→                <p className="text-sm text-muted-foreground">
355→                  No matching jobs.
356→                </p>
357→              ) : (
358→                <div className="space-y-2">
359→                  {jobs.map((job) => (
360→                    <JobItem
361→                      key={job.id}
362→                      job={job}
363→                      isSelected={selectedJobId === job.id}
364→                      isBusy={busy}
365→                      onSelect={() => handleSelectJob(job)}
366→                      onEdit={() => handleEdit(job)}
367→                      onToggle={() =>
368→                        toggle.mutate({
369→                          sandboxId,
370→                          jobId: job.id,
371→                          enabled: !job.enabled,
372→                        })
373→                      }
374→                      onRun={() => run.mutate({ sandboxId, jobId: job.id })}
375→                      onDelete={() => {
376→                        if (confirm(`Delete job "${job.name}"?`)) {
377→                          remove.mutate({ sandboxId, jobId: job.id });
378→                        }
379→                      }}
380→                    />
381→                  ))}
382→                </div>
383→              )}
384→            </div>
385→
386→            {/* Runs card */}
387→            {jobs.length > 0 && selectedJobId && (
388→              <div className="rounded-lg border p-4 bg-card">
389→                <div className="flex items-start justify-between gap-4 mb-3">
390→                  <div>
391→                    <h3 className="font-semibold">Run history</h3>
392→                    <p className="text-sm text-muted-foreground">
393→                      Latest runs for selected job.
394→                    </p>
395→                  </div>
396→                  <span className="text-sm text-muted-foreground shrink-0">
397→                    {runs.length} of {runsTotal}
398→                  </span>
399→                </div>
400→
401→                {runsLoading ? (
402→                  <p className="text-sm text-muted-foreground">
403→                    Loading runs...
404→                  </p>
405→                ) : runs.length === 0 ? (
406→                  <p className="text-sm text-muted-foreground">
407→                    No runs found.
408→                  </p>
409→                ) : (
410→                  <div className="space-y-2">
411→                    {runs.map((run) => (
412→                      <RunItem key={run.id} run={run} />
413→                    ))}
414→                  </div>
415→                )}
416→
417→                {runsHasMore && (
418→                  <div className="mt-3">
419→                    <Button
420→                      variant="outline"
421→                      size="sm"
422→                      disabled={runsLoading}
423→                      onClick={() => setRunsLimit((l) => l + 20)}
424→                    >
425→                      Load more
426→                    </Button>
427→                  </div>
428→                )}
429→              </div>
430→            )}
431→          </div>
432→
433→          {/* Right: Form */}
434→          {jobs.length > 0 && editingJobId && (
435→            <div className="lg:col-span-2">
436→              <CronForm
437→                form={form}
438→                isEditing={!!editingJobId}
439→                isBusy={busy}
440→                onChange={(patch) => setForm((prev) => ({ ...prev, ...patch }))}
441→                onSubmit={handleSubmit}
442→                onCancel={handleCancelEdit}
443→              />
444→            </div>
445→          )}
446→        </div>
447→      </div>
448→    </section>
449→  );
450→}
