  1→"use client";
  2→
  3→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
  4→import { toast } from "sonner";
  5→import {
  6→  deleteCronJob,
  7→  editCronJob,
  8→  getCronJobs,
  9→  getCronRuns,
 10→  getCronStatus,
 11→  runCronJob,
 12→  toggleCronJob,
 13→} from "@/server/actions/cron.actions";
 14→import type {
 15→  CronJob,
 16→  CronRunLogEntry,
 17→  CronStatus,
 18→} from "../_components/types";
 19→
 20→// ── Query keys ────────────────────────────────────────────────────────────────
 21→
 22→function statusKey(sandboxId: string) {
 23→  return ["cron-status", sandboxId] as const;
 24→}
 25→
 26→function jobsKey(sandboxId: string, params: object) {
 27→  return ["cron-jobs", sandboxId, params] as const;
 28→}
 29→
 30→function runsKey(sandboxId: string, params: object) {
 31→  return ["cron-runs", sandboxId, params] as const;
 32→}
 33→
 34→// ── Status ────────────────────────────────────────────────────────────────────
 35→
 36→export function useCronStatus(sandboxId: string | null) {
 37→  return useQuery({
 38→    queryKey: statusKey(sandboxId ?? ""),
 39→    queryFn: async () => {
 40→      const result = await getCronStatus({ sandboxId: sandboxId! });
 41→      if (result && typeof result === "object" && "error" in result) {
 42→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 43→      }
 44→      return result;
 45→    },
 46→    enabled: !!sandboxId,
 47→    select: (d) => d as CronStatus,
 48→  });
 49→}
 50→
 51→// ── Jobs ──────────────────────────────────────────────────────────────────────
 52→
 53→export interface CronJobsParams {
 54→  includeDisabled?: boolean;
 55→}
 56→
 57→export function useCronJobs(sandboxId: string | null, params: CronJobsParams = {}) {
 58→  return useQuery({
 59→    queryKey: jobsKey(sandboxId ?? "", params),
 60→    queryFn: async () => {
 61→      const result = await getCronJobs({
 62→        sandboxId: sandboxId!,
 63→        includeDisabled: params.includeDisabled ?? false,
 64→      });
 65→      if (result && typeof result === "object" && "error" in result) {
 66→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 67→      }
 68→      return result;
 69→    },
 70→    enabled: !!sandboxId,
 71→    select: (d) => {
 72→      const raw = d as { jobs: CronJob[]; total: number };
 73→      return { jobs: raw.jobs ?? [], total: raw.total ?? 0 };
 74→    },
 75→  });
 76→}
 77→
 78→// ── Runs ──────────────────────────────────────────────────────────────────────
 79→
 80→export interface CronRunsParams {
 81→  jobId?: string | null;
 82→  limit?: number;
 83→}
 84→
 85→export function useCronRuns(sandboxId: string | null, params: CronRunsParams = {}) {
 86→  return useQuery({
 87→    queryKey: runsKey(sandboxId ?? "", params),
 88→    queryFn: async () => {
 89→      const result = await getCronRuns({
 90→        sandboxId: sandboxId!,
 91→        jobId: params.jobId!,
 92→        limit: params.limit ?? 50,
 93→      });
 94→      if (result && typeof result === "object" && "error" in result) {
 95→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 96→      }
 97→      return result;
 98→    },
 99→    enabled: !!sandboxId && !!params.jobId,
100→    select: (d) => {
101→      const raw = d as { runs: CronRunLogEntry[]; total: number; hasMore: boolean };
102→      return { runs: raw.runs ?? [], total: raw.total ?? 0, hasMore: raw.hasMore ?? false };
103→    },
104→  });
105→}
106→
107→// ── Mutations ─────────────────────────────────────────────────────────────────
108→
109→export function useCronMutations(sandboxId: string | null) {
110→  const qc = useQueryClient();
111→
112→  function invalidate() {
113→    if (!sandboxId) return;
114→    void qc.invalidateQueries({ queryKey: ["cron-status", sandboxId] });
115→    void qc.invalidateQueries({ queryKey: ["cron-jobs", sandboxId] });
116→    void qc.invalidateQueries({ queryKey: ["cron-runs", sandboxId] });
117→  }
118→
119→
120→  const edit = useMutation({
121→    mutationFn: async (data: Parameters<typeof editCronJob>[0]) => {
122→      const result = await editCronJob(data);
123→      if (result && typeof result === "object" && "error" in result) {
124→        throw Object.assign(new Error(String(result.error)), { code: result.error });
125→      }
126→      return result;
127→    },
128→    onSuccess: () => {
129→      invalidate();
130→      toast.success("Job updated");
131→    },
132→    onError: (e) => toast.error(e instanceof Error ? e.message : "Failed to update job"),
133→  });
134→
135→  const remove = useMutation({
136→    mutationFn: async (data: Parameters<typeof deleteCronJob>[0]) => {
137→      const result = await deleteCronJob(data);
138→      if (result && typeof result === "object" && "error" in result) {
139→        throw Object.assign(new Error(String(result.error)), { code: result.error });
140→      }
141→      return result;
142→    },
143→    onSuccess: () => {
144→      invalidate();
145→      toast.success("Job deleted");
146→    },
147→    onError: (e) => toast.error(e instanceof Error ? e.message : "Failed to delete job"),
148→  });
149→
150→  const toggle = useMutation({
151→    mutationFn: async (data: Parameters<typeof toggleCronJob>[0]) => {
152→      const result = await toggleCronJob(data);
153→      if (result && typeof result === "object" && "error" in result) {
154→        throw Object.assign(new Error(String(result.error)), { code: result.error });
155→      }
156→      return result;
157→    },
158→    onSuccess: () => {
159→      invalidate();
160→      toast.success("Job updated");
161→    },
162→    onError: (e) => toast.error(e instanceof Error ? e.message : "Failed to toggle job"),
163→  });
164→
165→  const run = useMutation({
166→    mutationFn: async (data: Parameters<typeof runCronJob>[0]) => {
167→      const result = await runCronJob(data);
168→      if (result && typeof result === "object" && "error" in result) {
169→        throw Object.assign(new Error(String(result.error)), { code: result.error });
170→      }
171→      return result;
172→    },
173→    onSuccess: () => {
174→      invalidate();
175→      toast.success("Job triggered");
176→    },
177→    onError: (e) => toast.error(e instanceof Error ? e.message : "Failed to trigger job"),
178→  });
179→
180→  const busy = edit.isPending || remove.isPending || toggle.isPending || run.isPending;
181→
182→  return { edit, remove, toggle, run, busy };
183→}
