## Complete File Contents & Pattern Analysis

### 1. **Page Component** (`page.tsx`)
```tsx
"use client";
import { useParams } from "next/navigation";
import { CronView } from "@/app/(app)/sandboxes/[id]/cron/_components/cron-view";

export default function SandboxCronPage() {
